const launchCampaign = async (type: Campaign["type"], text: string) => {
  const token = typeof window !== "undefined" ? localStorage.getItem("outreach_token") : null;
  if (!token) { router.push("/auth"); return; }
  setLaunching(true);
  try {
    const data = await createCampaign(type);
    router.push("/campaign/" + data.campaign_id + "/wizard?msg=" + encodeURIComponent(text));
  } catch (error) {
    console.error("Failed to launch campaign:", error);
    setLaunching(false);
  }
};

